  ('bookkeeper-moex-01103', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年初成立並發行面額$10之普通股80,000股及面額$100、股利率3%符合權益之累積特別股 10,000股，該公司之發行股數至X3年底並無變動且仍全數流通在外。若該公司X1年與X3年未宣告任 何股利，X4年始宣告發放現金股利$70,000，則該公司普通股股東可得之現金股利金額為：', '["$0", "$10,000", "$40,000", "$70,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01104', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '承上題，甲公司X3年底特別股積欠股利應認列之負債金額為：', '["$0", "$10,000", "$20,000", "$30,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01105', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年底發行100張面額$100,000之轉換公司債得款$10,200,000，每張公司債得於到期日前之任 何時間轉換為100股甲公司普通股。經評估該公司債所含之轉換權於當日之公允價值為$400,000，且若該 公司於當日發行相同條件但不可轉換之公司債將可得款$9,900,000。若假設無交易成本，則該公司債所含 之轉換權X1年底之帳面金額為：', '["$200,000", "$300,000", "$396,117", "$400,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01106', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '承上題，惟每張公司債得於到期日前之任何時間轉換為價值$100,000之甲公司普通股。若假設無交易成本， 且經評估甲公司須將該公司債中之主契約與轉換權分離，則該公司債所含之轉換權X1年底之帳面金額為：', '["$200,000", "$300,000", "$396,117", "$400,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
